2589   // For equality predicates everything works.
2590   const bool RequiresNSW = !IsEquality && IsSigned;
2591   const bool RequiresNUW = !IsEquality && !IsSigned;
2592 
2593   // Try to represent VariantLHS as sum of invariant and variant operands.
2594   using namespace PatternMatch;
2595   Value *VariantOp, *InvariantOp;
