2597       !match(VariantLHS, m_AddLike(m_Value(VariantOp), m_Value(InvariantOp))))
2598     return false;
2599   if (RequiresNSW && !match(VariantLHS, m_NSWAddLike(m_Value(VariantOp),
2600                                                      m_Value(InvariantOp))))
2601     return false;
