2603                                                      m_Value(InvariantOp))))
2604     return false;
2605 
2606   // LHS itself is a loop-variant, try to represent it in the form:
2607   // "VariantOp + InvariantOp". If it is possible, then we can reassociate.
2608   if (L.isLoopInvariant(VariantOp))
2609     std::swap(VariantOp, InvariantOp);
