2645 /// Try to reassociate and hoist the following two patterns:
2646 /// LV - C1 < C2 --> LV < C1 + C2,
2647 /// C1 - LV < C2 --> LV > C1 - C2.
2648 static bool hoistSub(ICmpInst::Predicate Pred, Value *VariantLHS,
2649                      Value *InvariantRHS, ICmpInst &ICmp, Loop &L,
2650                      ICFLoopSafetyInfo &SafetyInfo, MemorySSAUpdater &MSSAU,
2651                      AssumptionCache *AC, DominatorTree *DT) {
2652   assert(!L.isLoopInvariant(VariantLHS) && "Precondition.");
2653   assert(L.isLoopInvariant(InvariantRHS) && "Precondition.");
2654 
2655   const bool IsSigned = ICmpInst::isSigned(Pred);
2656   const bool IsEquality = ICmpInst::isEquality(Pred);
2657 
2658   // For signed/unsigned predicates we need nsw/nuw respectively.
2659   // For equality predicates everything works.
2660   const bool RequiresNSW = !IsEquality && IsSigned;
2661   const bool RequiresNUW = !IsEquality && !IsSigned;
2662 
2663   // Try to represent VariantLHS as sum of invariant and variant operands.
2664   using namespace PatternMatch;
2665   Value *VariantOp, *InvariantOp;
2666   if (IsEquality &&
2667       !match(VariantLHS, m_Sub(m_Value(VariantOp), m_Value(InvariantOp))))
2668     return false;
2669   if (RequiresNSW &&
2670       !match(VariantLHS, m_NSWSub(m_Value(VariantOp), m_Value(InvariantOp))))
2671     return false;
2672   if (RequiresNUW &&
2673       !match(VariantLHS, m_NUWSub(m_Value(VariantOp), m_Value(InvariantOp))))
2674     return false;
2675 
2676   bool VariantSubtracted = false;
2677   // LHS itself is a loop-variant, try to represent it in the form:
2678   // "VariantOp + InvariantOp". If it is possible, then we can reassociate. If
2679   // the variant operand goes with minus, we use a slightly different scheme.
2680   if (L.isLoopInvariant(VariantOp)) {
2681     std::swap(VariantOp, InvariantOp);
2682     VariantSubtracted = true;
2683     Pred = ICmpInst::getSwappedPredicate(Pred);
2684   }
2685   if (L.isLoopInvariant(VariantOp) || !L.isLoopInvariant(InvariantOp))
2686     return false;
2687 
2688   // In order to turn "LV - C1 < C2" into "LV < C2 + C1", we need to be able to
2689   // freely move values from left side of inequality to right side (just as in
2690   // normal linear arithmetics). Overflows make things much more complicated, so
2691   // we want to avoid this. Likewise, for "C1 - LV < C2" we need to prove that
2692   // "C1 - C2" does not overflow.
2693   auto &DL = L.getHeader()->getDataLayout();
2694   SimplifyQuery SQ(DL, DT, AC, &ICmp);
