2696     // C1 - LV < C2 --> LV > C1 - C2
2697     if (computeOverflowForSignedSub(InvariantOp, InvariantRHS, SQ) !=
2698         llvm::OverflowResult::NeverOverflows)
2699       return false;
2700   } else if (VariantSubtracted && RequiresNUW) {
2701     // C1 - LV < C2 --> LV > C1 - C2
2702     if (computeOverflowForUnsignedSub(InvariantOp, InvariantRHS, SQ) !=
2703         llvm::OverflowResult::NeverOverflows)
2704       return false;
2705   } else if (!VariantSubtracted && RequiresNSW) {
2706     // LV - C1 < C2 --> LV < C1 + C2
2707     if (computeOverflowForSignedAdd(InvariantOp, InvariantRHS, SQ) !=
2708         llvm::OverflowResult::NeverOverflows)
2709       return false;
2710   } else if (!VariantSubtracted && RequiresNUW) {
2711     // LV - C1 < C2 --> LV < C1 + C2
2712     if (computeOverflowForUnsignedAdd(InvariantOp, InvariantRHS, SQ) !=
2713         llvm::OverflowResult::NeverOverflows)
2714       return false;
2715   }
2716   auto *Preheader = L.getLoopPreheader();
2717   assert(Preheader && "Loop is not in simplify form?");
2718   IRBuilder<> Builder(Preheader->getTerminator());
2719   Value *NewCmpOp =
2720       VariantSubtracted
2721           ? Builder.CreateSub(InvariantOp, InvariantRHS, "invariant.op",
2722                               /*HasNUW*/ RequiresNUW,
2723                               /*HasNSW*/ RequiresNSW)
2724           : Builder.CreateAdd(InvariantOp, InvariantRHS, "invariant.op",
2725                               /*HasNUW*/ RequiresNUW,
2726                               /*HasNSW*/ RequiresNSW);
2727   ICmp.setPredicate(Pred);
2728   ICmp.setOperand(0, VariantOp);
2729   ICmp.setOperand(1, NewCmpOp);
2730 
2731   Instruction &DeadI = cast<Instruction>(*VariantLHS);
2732   salvageDebugInfo(DeadI);
