2737 /// Reassociate and hoist add/sub expressions.
2738 static bool hoistAddSub(Instruction &I, Loop &L, ICFLoopSafetyInfo &SafetyInfo,
2739                         MemorySSAUpdater &MSSAU, AssumptionCache *AC,
2740                         DominatorTree *DT) {
2741   using namespace PatternMatch;
2742   CmpPredicate Pred;
2743   Value *LHS, *RHS;
2744   if (!match(&I, m_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
2745     return false;
2746 
2747   // Put variant operand to LHS position.
2748   if (L.isLoopInvariant(LHS)) {
2749     std::swap(LHS, RHS);
2750     Pred = ICmpInst::getSwappedPredicate(Pred);
2751   }
2752   // We want to delete the initial operation after reassociation, so only do it
2753   // if it has no other uses.
2754   if (L.isLoopInvariant(LHS) || !L.isLoopInvariant(RHS) || !LHS->hasOneUse())
2755     return false;
2756 
2757   // TODO: We could go with smarter context, taking common dominator of all I's
2758   // users instead of I itself.
2759   if (hoistAdd(Pred, LHS, RHS, cast<ICmpInst>(I), L, SafetyInfo, MSSAU, AC, DT))
2760     return true;
2761 
2762   if (hoistSub(Pred, LHS, RHS, cast<ICmpInst>(I), L, SafetyInfo, MSSAU, AC, DT))
2763     return true;
2764 
2765   return false;
2766 }
