2768 static bool isReassociableOp(Instruction *I, unsigned IntOpcode,
2769                              unsigned FPOpcode) {
2770   if (I->getOpcode() == IntOpcode)
2771     return true;
2772   if (I->getOpcode() == FPOpcode && I->hasAllowReassoc() &&
2773       I->hasNoSignedZeros())
2774     return true;
2775   return false;
2776 }
