2778 /// Try to reassociate expressions like ((A1 * B1) + (A2 * B2) + ...) * C where
2779 /// A1, A2, ... and C are loop invariants into expressions like
2780 /// ((A1 * C * B1) + (A2 * C * B2) + ...) and hoist the (A1 * C), (A2 * C), ...
2781 /// invariant expressions. This functions returns true only if any hoisting has
2782 /// actually occurred.
2783 static bool hoistMulAddAssociation(Instruction &I, Loop &L,
2784                                    ICFLoopSafetyInfo &SafetyInfo,
2785                                    MemorySSAUpdater &MSSAU, AssumptionCache *AC,
2786                                    DominatorTree *DT) {
2787   if (!isReassociableOp(&I, Instruction::Mul, Instruction::FMul))
2788     return false;
2789   Value *VariantOp = I.getOperand(0);
2790   Value *InvariantOp = I.getOperand(1);
2791   if (L.isLoopInvariant(VariantOp))
2792     std::swap(VariantOp, InvariantOp);
2793   if (L.isLoopInvariant(VariantOp) || !L.isLoopInvariant(InvariantOp))
2794     return false;
2795   Value *Factor = InvariantOp;
2796 
2797   // First, we need to make sure we should do the transformation.
2798   SmallVector<Use *> Changes;
2799   SmallVector<BinaryOperator *> Adds;
2800   SmallVector<BinaryOperator *> Worklist;
2801   if (BinaryOperator *VariantBinOp = dyn_cast<BinaryOperator>(VariantOp))
2802     Worklist.push_back(VariantBinOp);
2803   while (!Worklist.empty()) {
2804     BinaryOperator *BO = Worklist.pop_back_val();
2805     if (!BO->hasOneUse())
2806       return false;
2807     if (isReassociableOp(BO, Instruction::Add, Instruction::FAdd) &&
2808         isa<BinaryOperator>(BO->getOperand(0)) &&
2809         isa<BinaryOperator>(BO->getOperand(1))) {
2810       Worklist.push_back(cast<BinaryOperator>(BO->getOperand(0)));
2811       Worklist.push_back(cast<BinaryOperator>(BO->getOperand(1)));
2812       Adds.push_back(BO);
2813       continue;
2814     }
2815     if (!isReassociableOp(BO, Instruction::Mul, Instruction::FMul) ||
2816         L.isLoopInvariant(BO))
2817       return false;
2818     Use &U0 = BO->getOperandUse(0);
2819     Use &U1 = BO->getOperandUse(1);
2820     if (L.isLoopInvariant(U0))
2821       Changes.push_back(&U0);
2822     else if (L.isLoopInvariant(U1))
2823       Changes.push_back(&U1);
2824     else
2825       return false;
2826     unsigned Limit = I.getType()->isIntOrIntVectorTy()
2827                          ? IntAssociationUpperLimit
2828                          : FPAssociationUpperLimit;
2829     if (Changes.size() > Limit)
2830       return false;
2831   }
2832   if (Changes.empty())
2833     return false;
2834 
2835   // Drop the poison flags for any adds we looked through.
2836   if (I.getType()->isIntOrIntVectorTy()) {
2837     for (auto *Add : Adds)
2838       Add->dropPoisonGeneratingFlags();
2839   }
2840 
2841   // We know we should do it so let's do the transformation.
2842   auto *Preheader = L.getLoopPreheader();
2843   assert(Preheader && "Loop is not in simplify form?");
2844   IRBuilder<> Builder(Preheader->getTerminator());
2845   for (auto *U : Changes) {
2846     assert(L.isLoopInvariant(U->get()));
2847     auto *Ins = cast<BinaryOperator>(U->getUser());
2848     Value *Mul;
2849     if (I.getType()->isIntOrIntVectorTy()) {
2850       Mul = Builder.CreateMul(U->get(), Factor, "factor.op.mul");
2851       // Drop the poison flags on the original multiply.
2852       Ins->dropPoisonGeneratingFlags();
2853     } else
2854       Mul = Builder.CreateFMulFMF(U->get(), Factor, Ins, "factor.op.fmul");
2855 
2856     // Rewrite the reassociable instruction.
2857     unsigned OpIdx = U->getOperandNo();
2858     auto *LHS = OpIdx == 0 ? Mul : Ins->getOperand(0);
2859     auto *RHS = OpIdx == 1 ? Mul : Ins->getOperand(1);
2860     auto *NewBO =
2861         BinaryOperator::Create(Ins->getOpcode(), LHS, RHS,
2862                                Ins->getName() + ".reass", Ins->getIterator());
2863     NewBO->setDebugLoc(DebugLoc::getDropped());
2864     NewBO->copyIRFlags(Ins);
2865     if (VariantOp == Ins)
2866       VariantOp = NewBO;
2867     Ins->replaceAllUsesWith(NewBO);
2868     eraseInstruction(*Ins, SafetyInfo, MSSAU);
2869   }
2870 
2871   I.replaceAllUsesWith(VariantOp);
2872   eraseInstruction(I, SafetyInfo, MSSAU);
2873   return true;
2874 }
