2876 /// Reassociate associative binary expressions of the form
2877 ///
2878 /// 1. "(LV op C1) op C2" ==> "LV op (C1 op C2)"
2879 /// 2. "(C1 op LV) op C2" ==> "LV op (C1 op C2)"
2880 /// 3. "C2 op (C1 op LV)" ==> "LV op (C1 op C2)"
2881 /// 4. "C2 op (LV op C1)" ==> "LV op (C1 op C2)"
2882 ///
2883 /// where op is an associative BinOp, LV is a loop variant, and C1 and C2 are
2884 /// loop invariants that we want to hoist, noting that associativity implies
2885 /// commutativity.
2886 static bool hoistBOAssociation(Instruction &I, Loop &L,
2887                                ICFLoopSafetyInfo &SafetyInfo,
2888                                MemorySSAUpdater &MSSAU, AssumptionCache *AC,
2889                                DominatorTree *DT) {
2890   auto *BO = dyn_cast<BinaryOperator>(&I);
2891   if (!BO || !BO->isAssociative())
2892     return false;
2893 
2894   Instruction::BinaryOps Opcode = BO->getOpcode();
2895   bool LVInRHS = L.isLoopInvariant(BO->getOperand(0));
2896   auto *BO0 = dyn_cast<BinaryOperator>(BO->getOperand(LVInRHS));
2897   if (!BO0 || BO0->getOpcode() != Opcode || !BO0->isAssociative() ||
2898       BO0->hasNUsesOrMore(BO0->getType()->isIntegerTy() ? 2 : 3))
2899     return false;
2900 
2901   Value *LV = BO0->getOperand(0);
2902   Value *C1 = BO0->getOperand(1);
2903   Value *C2 = BO->getOperand(!LVInRHS);
2904 
2905   assert(BO->isCommutative() && BO0->isCommutative() &&
2906          "Associativity implies commutativity");
2907   if (L.isLoopInvariant(LV) && !L.isLoopInvariant(C1))
2908     std::swap(LV, C1);
2909   if (L.isLoopInvariant(LV) || !L.isLoopInvariant(C1) || !L.isLoopInvariant(C2))
2910     return false;
2911 
2912   auto *Preheader = L.getLoopPreheader();
2913   assert(Preheader && "Loop is not in simplify form?");
2914 
2915   IRBuilder<> Builder(Preheader->getTerminator());
2916   auto *Inv = Builder.CreateBinOp(Opcode, C1, C2, "invariant.op");
2917 
2918   auto *NewBO = BinaryOperator::Create(
2919       Opcode, LV, Inv, BO->getName() + ".reass", BO->getIterator());
2920   NewBO->setDebugLoc(DebugLoc::getDropped());
2921 
2922   if (Opcode == Instruction::FAdd || Opcode == Instruction::FMul) {
2923     // Intersect FMF flags for FADD and FMUL.
2924     FastMathFlags Intersect = BO->getFastMathFlags() & BO0->getFastMathFlags();
2925     if (auto *I = dyn_cast<Instruction>(Inv))
2926       I->setFastMathFlags(Intersect);
2927     NewBO->setFastMathFlags(Intersect);
2928   } else {
2929     OverflowTracking Flags;
2930     Flags.AllKnownNonNegative = false;
2931     Flags.AllKnownNonZero = false;
2932     Flags.mergeFlags(*BO);
2933     Flags.mergeFlags(*BO0);
2934     // If `Inv` was not constant-folded, a new Instruction has been created.
2935     if (auto *I = dyn_cast<Instruction>(Inv))
2936       Flags.applyFlags(*I);
2937     Flags.applyFlags(*NewBO);
2938   }
2939 
2940   BO->replaceAllUsesWith(NewBO);
2941   eraseInstruction(*BO, SafetyInfo, MSSAU);
2942 
2943   // (LV op C1) might not be erased if it has more uses than the one we just
2944   // replaced.
2945   if (BO0->use_empty()) {
2946     salvageDebugInfo(*BO0);
2947     eraseInstruction(*BO0, SafetyInfo, MSSAU);
2948   }
2949 
2950   return true;
2951 }
2952 
2953 static bool hoistArithmetics(Instruction &I, Loop &L,
2954                              ICFLoopSafetyInfo &SafetyInfo,
2955                              MemorySSAUpdater &MSSAU, AssumptionCache *AC,
2956                              DominatorTree *DT) {
2957   // Optimize complex patterns, such as (x < INV1 && x < INV2), turning them
2958   // into (x < min(INV1, INV2)), and hoisting the invariant part of this
2959   // expression out of the loop.
2960   if (hoistMinMax(I, L, SafetyInfo, MSSAU)) {
2961     ++NumHoisted;
2962     ++NumMinMaxHoisted;
2963     return true;
2964   }
2965 
2966   // Try to hoist GEPs by reassociation.
2967   if (hoistGEP(I, L, SafetyInfo, MSSAU, AC, DT)) {
2968     ++NumHoisted;
2969     ++NumGEPsHoisted;
2970     return true;
2971   }
2972 
2973   // Try to hoist add/sub's by reassociation.
2974   if (hoistAddSub(I, L, SafetyInfo, MSSAU, AC, DT)) {
2975     ++NumHoisted;
2976     ++NumAddSubHoisted;
2977     return true;
2978   }
